INSERT INTO `ci_cms_pages` (`page_id`, `page_name`, `page_type`, `page_description`, `lang`, `is_active`) VALUES
(1, 'Privacy Policy', 'footer', '..', 'en', 1),
(2, 'Terms & Conditions', 'footer', '..', 'en', 1),
(3, 'Home Page', 'main_content', '&lt;section class=&#34;services__area grey-bg-3 pt-120 mt-0 pb-60 p-relative&#34;&gt;&lt;div class=&#34;services__shape-2&#34;&gt;&lt;img class=&#34;services-2-circle&#34; src=&#34;http://localhost/cz/timehrm_local_dav/public/frontend/assets/img/icon/services/home-2/services-circle.png&#34; alt=&#34;&#34; /&gt;&lt;img class=&#34;services-2-circle-2&#34; src=&#34;http://localhost/cz/timehrm_local_dav/public/frontend/assets/img/icon/services/home-2/services-circle-2.png&#34; alt=&#34;&#34; /&gt;&lt;/div&gt;&lt;div class=&#34;container&#34;&gt;&lt;div class=&#34;row align-items-end&#34;&gt;&lt;div class=&#34;col-xxl-4 col-lg-5 col-md-7&#34;&gt;&lt;div class=&#34;section__title-wrapper mb-70 wow fadeInUp&#34; data-wow-delay=&#34;.3s&#34; style=&#34;visibility:visible;animation-delay:0.3s;animation-name:fadeInUp;&#34;&gt;&lt;span class=&#34;section__pre-title purple&#34;&gt;REASONS WHY&lt;/span&gt; &lt;h2 class=&#34;section__title section__title-2&#34;&gt;Everything you need in one HR software.&lt;/h2&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&#34;col-xxl-8 col-lg-7 col-md-5&#34;&gt;&lt;div class=&#34;services__more mb-70 text-sm-end wow fadeInUp&#34; data-wow-delay=&#34;.5s&#34; style=&#34;visibility:visible;animation-delay:0.5s;animation-name:fadeInUp;&#34;&gt;&lt;a href=&#34;features&#34; class=&#34;w-btn w-btn-blue w-btn-6 w-btn-3&#34;&gt;view more&lt;/a&gt; &lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div class=&#34;row&#34;&gt;&lt;div class=&#34;col-xxl-4 col-xl-4 col-lg-4 col-md-6 wow fadeInUp&#34; data-wow-delay=&#34;.3s&#34; style=&#34;visibility:visible;animation-delay:0.3s;animation-name:fadeInUp;&#34;&gt;&lt;div class=&#34;services__inner services__inner-2 hover__active mb-30&#34;&gt;&lt;div class=&#34;services__item-2 transition-3 white-bg &#34;&gt;&lt;div class=&#34;services__icon-2&#34;&gt;&lt;img src=&#34;http://localhost/cz/timehrm_local_dav/public/frontend/assets/img/icon/services/home-2/services-1.png&#34; alt=&#34;&#34; /&g