Up;&#34;&gt;&lt;div class=&#34;services__item-4 white-bg mb-30&#34;&gt;&lt;div class=&#34;services__thumb-4 text-center d-flex align-items-end justify-content-center&#34;&gt;&lt;img src=&#34;http://localhost/cz/timehrm_local_dav/public/frontend/assets/img/services/home-4/services-2.png&#34; alt=&#34;&#34; /&gt;&lt;/div&gt;&lt;div class=&#34;services__content-4&#34;&gt;&lt;h3 class=&#34;services__title-4&#34;&gt;&lt;a href=&#34;#!&#34;&gt;Performance&lt;/a&gt;&lt;/h3&gt;&lt;p&gt;Empower and engage high performers by setting clear goals and streamlining employee appraisal and feedback processes. Focus on productivity, creating a thriving company culture.&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/section&gt;&lt;section class=&#34;cta__area blue-bg-10 pt-140 pb-130 p-relative fix z-index-1&#34;&gt;&lt;div class=&#34;cta__shape&#34;&gt;&lt;img class=&#34;cta-4-shape&#34; src=&#34;http://localhost/cz/timehrm_local_dav/public/frontend/assets/img/cta/home-4/cta-shape.png&#34; alt=&#34;&#34; /&gt;&lt;/div&gt;&lt;div class=&#34;container&#34;&gt;&lt;div class=&#34;row&#34;&gt;&lt;div class=&#34;col-xxl-8 offset-xxl-2&#34;&gt;&lt;div class=&#34;cta__content-4 text-center&#34;&gt;&lt;div class=&#34;section__title-wrapper section__title-wrapper-4 section__title-white text-center mb-45 wow fadeInUp&#34; data-wow-delay=&#34;.3s&#34; style=&#34;visibility:visible;animation-delay:0.3s;animation-name:fadeInUp;&#34;&gt;&lt;h2 class=&#34;section__title section__title-4&#34;&gt;Our Free Trial for 14-days Today&lt;/h2&gt;&lt;p&gt;Spend less time scheduling and more time investing in your team and business.&lt;/p&gt;&lt;/div&gt;&lt;div class=&#34;cta__form mb-25 wow fadeInUp&#34; data-wow-delay=&#34;.5s&#34; style=&#34;visibility:visible;animation-delay:0.5s;animation-name:fadeInUp;&#34;&gt;&lt;a href=&#34;register&#34; class=&#34;w-btn w-btn-3 w-btn-1&#34;&gt;Start Free Trial&lt;/a&gt; &lt;/div&gt;&lt;div class=&#34;cta__features wow fadeInUp&#34; data-wow-delay=&#34;.7s&#34; style=&#34;visibility:visible;animation-delay:0.7s;animation-name:fadeInUp;&#34;&gt;&lt;ul&gt;&lt;li&gt;Product support&lt;/li&gt;&lt;li&gt;Free Trial&lt;/li&gt;&lt;li&gt;Connect Customer&lt;/li&gt;&lt;/ul&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/section&gt;', 'en', 0),
