(1, 'code1', 'super_admin', 'Forgot Password', 'Forgot Password', '&lt;p&gt;&lt;span style=\"forced-color-adjust:none;color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;background-color:#ffffff;\"&gt;Hi There,&lt;/span&gt;&lt;/p&gt;&lt;p&gt;&lt;span style=\"forced-color-adjust:none;color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;background-color:#ffffff;\"&gt;There was recently a request for password for your {site_name} account.&lt;/span&gt;&lt;/p&gt;&lt;p style=\"margin-bottom:1rem;box-sizing:border-box;color:#4e5155;font-family:Roboto, -apple-system, BlinkMacSystemFont, \'Segoe UI\', Oxygen, Ubuntu, Cantarell, \'Fira Sans\', \'Droid Sans\', \'Helvetica Neue\', sans-serif;font-size:14.304px;background-color:#ffffff;\"&gt;&lt;span style=\"forced-color-adjust:none;color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;\"&gt;To reset password, visit the following link&lt;/span&gt;&amp;nbsp;&lt;a href=\"{site_url}erp/verified-password?v={user_id}\" title=\"Reset Password\" target=\"_blank\"&gt;&lt;strong&gt;&lt;span style=\"forced-color-adjust:none;color:#6699cc;\"&gt;Reset Password&lt;/span&gt;&lt;/strong&gt;&lt;/a&gt;&lt;/p&gt;&lt;p style=\"margin-bottom:1rem;box-sizing:border-box;color:#4e5155;font-family:Roboto, -apple-system, BlinkMacSystemFont, \'Segoe UI\', Oxygen, Ubuntu, Cantarell, \'Fira Sans\', \'Droid Sans\', \'Helvetica Neue\', sans-serif;font-size:14.304px;background-color:#ffffff;\"&gt;&lt;span style=\"forced-color-adjust:none;color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;\"&gt;If this was a mistake, just ignore this email and nothing will happen.&lt;/span&gt;&lt;/p&gt;&lt;p style=\"margin-bottom:1rem;box-sizing:border-box;color:#4e5155;font-family:Roboto, -apple-system, BlinkMacSystemFont, \'Segoe UI\', Oxygen, Ubuntu, Cantarell, \'Fira Sans\', \'Droid Sans\', \'Helvetica Neue\', sans-serif;font-size:14.304px;background-color:#ffffff;\"&gt;&lt;span style=\"forced-color-adjust:none;color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;\"&gt;----&lt;/span&gt;&lt;br style=\"color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;box-sizing:border-box;\" /&gt;&lt;span style=\"forced-color-adjust:none;color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;\"&gt;Thank You,&lt;/span&gt;&lt;br style=\"color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;box-sizing:border-box;\" /&gt;&lt;span style=\"forced-color-adjust:none;color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;\"&gt;{site_name}&lt;/span&gt;&lt;/p&gt;', 1, 'en', 1),
(2, 'code1', 'super_admin', 'Password Changed Successfully', 'Password Changed Successfully', '&lt;p style=\"margin-bottom:1rem;box-sizing:border-box;color:#4e5155;font-family:Roboto, -apple-system, BlinkMacSystemFont, \'Segoe UI\', Oxygen, Ubuntu, Cantarell, \'Fira Sans\', \'Droid Sans\', \'Helvetica Neue\', sans-serif;font-size:14.304px;background-color:#ffffff;\"&gt;&lt;span style=\"forced-color-adjust:none;color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;\"&gt;Hi There,&lt;/span&gt;&lt;/p&gt;&lt;p style=\"margin-bottom:1rem;box-sizing:border-box;color:#4e5155;font-family:Roboto, -apple-system, BlinkMacSystemFont, \'Segoe UI\', Oxygen, Ubuntu, Cantarell, \'Fira Sans\', \'Droid Sans\', \'Helvetica Neue\', sans-serif;font-size:14.304px;background-color:#ffffff;\"&gt;&lt;span style=\"forced-color-adjust:none;color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;\"&gt;Congratulations! Your password has been updated successfully.&lt;/span&gt;&lt;/p&gt;&lt;p style=\"margin-bottom:1rem;box-sizing:border-box;color:#4e5155;font-family:Roboto, -apple-system, BlinkMacSystemFont, \'Segoe UI\', Oxygen, Ubuntu, Cantarell, \'Fira Sans\', \'Droid Sans\', \'Helvetica Neue\', sans-serif;font-size:14.304px;background-color:#ffffff;\"&gt;&lt;span style=\"forced-color-adjust:none;color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;\"&gt;Your Username is: {username}&lt;/span&gt;&lt;/p&gt;&lt;p style=\"margin-bottom:1rem;box-sizing:border-box;color:#4e5155;font-family:Roboto, -apple-system, BlinkMacSystemFont, \'Segoe UI\', Oxygen, Ubuntu, Cantarell, \'Fira Sans\', \'Droid Sans\', \'Helvetica Neue\', sans-serif;font-size:14.304px;background-color:#ffffff;\"&gt;&lt;span style=\"forced-color-adjust:none;color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;\"&gt;Your new password is: {password}&lt;/span&gt;&lt;br /&gt;&lt;/p&gt;&lt;span style=\"color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;background-color:#ffffff;\"&gt;----&lt;/span&gt;&lt;br style=\"color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;box-sizing:border-box;\" /&gt;&lt;span style=\"color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;background-color:#ffffff;\"&gt;Thank You,&lt;/span&gt;&lt;br style=\"color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;box-sizing:border-box;\" /&gt;&lt;span style=\"forced-color-adjust:none;color:#8094ae;font-family:Roboto, sans-serif, \'Helvetica Neue\', Arial, \'Noto Sans\', sans-serif;font-size:14px;background-color:#ffffff;\"&gt;{site_name}&lt;/span&gt;', 1, 'en', 2),
(3, 'code1', 'super_admin', 'Add New Company | From Backend', 'Warm Welcome', '&lt;p style=&#34;margin-bottom:1rem;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;&lt;span style=&#34;forced-color-adjust:none;box-sizing:border-box;&#34;&gt;Hello {user_name}&lt;/span&gt;,&lt;/p&gt;&lt;p style=&#34;margin-bottom:1rem;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;Welcome to {site_name}. Your subscription plan is {plan_title}&lt;/p&gt;&lt;p style=&#34;margin-bottom:1rem;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;We have listed your sign-in details below, please make sure you keep them safe.&lt;/p&gt;&lt;p style=&#34;margin-bottom:1rem;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;Your Username is: {user_username}&lt;/p&gt;&lt;p style=&#34;margin-bottom:1rem;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;Your Password is: {user_password}&lt;/p&gt;&lt;p style=&#34;margin-bottom:1rem;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;&lt;a href=&#34;{site_url}erp/login&#34; title=&#34;Login Here&#34; target=&#34;_blank&#34;&gt;Login Here&lt;/a&gt;&lt;/p&gt;&lt;p class=&#34;mt-4&#34; style=&#34;margin-bottom:0px;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;margin-top:1.5rem !important;&#34;&gt;----&lt;br style=&#34;box-sizing:border-box;&#34; /&gt;Thank You&lt;br style=&#34;box-sizing:border-box;&#34; /&gt;&lt;span style=&#34;forced-color-adjust:none;&#34;&gt;{site_name}&lt;/span&gt;&lt;/p&gt;', 1, 'en', 3),
(4, 'code1', 'super_admin', 'Signup Company | From Frontend', 'Verify your email', '&lt;p style=&#34;margin-bottom:1rem;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;&lt;span style=&#34;forced-color-adjust:none;box-sizing:border-box;&#34;&gt;Welcome {user_name}&lt;/span&gt;,&lt;/p&gt;&lt;p style=&#34;margin-bottom:1rem;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;You are receiving this email because you have registered on our site.&lt;/p&gt;&lt;p style=&#34;margin-bottom:1rem;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;Your Username is: {user_username}&lt;/p&gt;&lt;p style=&#34;margin-bottom:1rem;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;Your Username is: {user_password}&lt;/p&gt;&lt;p style=&#34;margin-bottom:1rem;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;Click the link below to active your {site_name} account as a Trial version.&lt;/p&gt;&lt;p style=&#34;margin-bottom:1rem;box-sizing:border-box;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;&lt;span style=&#34;color:#8094ae;font-family:Roboto, sans-serif, &#39;Helvetica Neue&#39;, Arial, &#39;Noto Sans&#39;, sans-serif;font-size:14px;background-color:#ffffff;&#34;&gt;Note: Above username and password will not work until you a