(11, 142, 'الرياض - حي الروضة', 219, 1, 2, '0', '3', '2023-04-29', 'مطلوب مسوق احترافي بمجال تقنية المعلومات والبرامج المحاسبية وبرامج شؤون الموظفين ولدية معرفة بتقنية الذكاء الاصطناعي يجب ان يكون لديه شهادة البكالوريوس&amp;nbsp; ولديه خبرة لا تقل عن 3 سنوات في التسويق ولديه المعرفة بمدينة الرياض ولديه رخصة قيادة سارية والاولوية للسعوديين&amp;nbsp;', '', 1, '29-04-2023 04:26:30'),
(12, 142, 'الرياض - حي الروضة', 220, 1, 2, '0', '3', '2023-04-29', 'مطلوب مبرمج&amp;nbsp; بمجال تقنية المعلومات والبرامج المحاسبية وبرامج شؤون الموظفين وبرمجة التطبيقات ولدية معرفة بتقنية الذكاء الاصطناعي يجب ان يكون يحمل شهادة البكالوريوس او الماجستير&amp;nbsp; ولديه خبرة عمل لا تقل عن 3 سنوات والاولوية للسعوديين&amp;nbsp;', '', 1, '29-04-2023 04:31:33'),
